## 4. 개선된 전체 매칭 서비스

**After (최적화된 코드)**

파일 위치: `domain/src/main/kotlin/com/maum/backend/service/call/CallMatchingService.kt`

```kotlin
@Service
@Transactional(readOnly = true)
class CallMatchingService(
    private val matchQueueService: MatchQueueService,
    private val callRepository: CallRepository,
    private val blockRepository: BlockRepository,
    private val redisTemplate: RedisTemplate<String, String>,
) {
    private val valueOps = redisTemplate.opsForValue()

    @Transactional
    fun requestMatch(userId: String, preference: MatchPreference): MatchResult {
        // 1. 분산 락으로 동시 요청 방지
        if (!matchQueueService.acquireMatchLock(userId)) {
            return MatchResult.ALREADY_PROCESSING
        }

        return try {
            // 2. 제외 대상 수집 (Redis 캐시 활용)
            val excludeIds = getExcludeIds(userId)

            // 3. Redis 대기열에서 후보 조회 (DB 미접근)
            val redisCandidates = matchQueueService.getCandidates(
                excludeIds = excludeIds + userId,
                limit = 5
            )

            if (redisCandidates.isNotEmpty()) {
                // 4a. Redis에서 바로 매칭 처리 (DB 쿼리 0)
                executeMatch(userId, redisCandidates.first())
            } else {
                // 4b. Redis 미스 시 DB에서 단일 쿼리로 조회 (fetch join + projection)
                val dbCandidates = callRepository.findMatchCandidatesWithProfile(
                    excludeUserIds = excludeIds + userId,
                    limit = 5
                )
                dbCandidates.firstOrNull()
                    ?.let { executeMatch(userId, it.userId) }
                    ?: MatchResult.NO_CANDIDATE
            }
        } finally {
            matchQueueService.releaseMatchLock(userId)
        }
    }

    // 제외 대상 수집: 차단 목록 + 최근 매칭 이력 (Redis 캐시)
    private fun getExcludeIds(userId: String): Set<String> {
        val blockedKey = RedisKey.blockedIds(userId)
        val recentKey = RedisKey.recentMatches(userId)

        // Redis에서 캐시 조회
        val cachedBlocked = redisTemplate.opsForSet().members(blockedKey)
        val cachedRecent = redisTemplate.opsForSet().members(recentKey)

        val blocked = if (cachedBlocked.isNullOrEmpty()) {
            // 캐시 미스: DB 조회 후 캐시 저장
            blockRepository.findBlockedIdsByUserId(userId).also { ids ->
                if (ids.isNotEmpty()) {
                    redisTemplate.opsForSet().add(blockedKey, *ids.toTypedArray())
                    redisTemplate.expire(blockedKey, Duration.ofMinutes(5))
                }
            }.toSet()
        } else {
            cachedBlocked
        }

        val recent = cachedRecent ?: emptySet()
        return blocked + recent
    }

    @Transactional
    private fun executeMatch(requesterId: String, targetId: String): MatchResult {
        // 대기열에서 양쪽 제거
        matchQueueService.dequeue(requesterId, targetId)

        // 최근 매칭 이력 Redis에 기록 (양방향)
        recordRecentMatch(requesterId, targetId)
        recordRecentMatch(targetId, requesterId)

        // DB에 매칭 결과 저장
        val callSession = callSessionRepository.save(
            CallSessionEntity(requesterId = requesterId, responderId = targetId)
        )
        return MatchResult.Matched(callSession.id)
    }

    private fun recordRecentMatch(userId: String, matchedId: String) {
        val key = RedisKey.recentMatches(userId)
        redisTemplate.opsForSet().add(key, matchedId)
        redisTemplate.expire(key, Duration.ofMinutes(30))
    }
}
```

