@Service
class MatchQueueService(
    private val redisTemplate: RedisTemplate<String, String>,
    private val stringRedisTemplate: StringRedisTemplate,
) {
    private val zSetOps = redisTemplate.opsForZSet()
    private val valueOps = redisTemplate.opsForValue()

    // 매칭 대기열 진입: score = 요청 timestamp (오래 기다린 순 우선)
    fun enqueue(userId: String, preferences: MatchPreference) {
        val score = System.currentTimeMillis().toDouble()
        zSetOps.add(RedisKey.MATCH_QUEUE, userId, score)

        // 선호 조건을 별도 Hash에 저장
        redisTemplate.opsForHash<String, String>()
            .putAll("match:pref:$userId", preferences.toMap())
        redisTemplate.expire("match:pref:$userId", Duration.ofMinutes(10))
    }

    // 대기열에서 후보 조회 (오래 기다린 순)
    fun getCandidates(excludeIds: Set<String>, limit: Long = 20): List<String> {
        val allWaiting = zSetOps.range(RedisKey.MATCH_QUEUE, 0, limit * 3 + excludeIds.size)
            ?: return emptyList()
        return allWaiting.filter { it !in excludeIds }.take(limit.toInt())
    }

    // 매칭 완료 시 대기열에서 제거
    fun dequeue(vararg userIds: String) {
        zSetOps.remove(RedisKey.MATCH_QUEUE, *userIds)
    }

    // 분산 락으로 동시 매칭 요청 방지
    fun acquireMatchLock(userId: String): Boolean {
        return valueOps.setIfAbsent(
            RedisKey.matchLock(userId),
            "1",
            Duration.ofSeconds(10)
        ) == true
    }

    fun releaseMatchLock(userId: String) {
        redisTemplate.delete(RedisKey.matchLock(userId))
    }
}
