```kotlin
@Repository
class CallRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : CallRepositoryCustom {

    // After: 단일 쿼리로 매칭 후보 + 프로필 한 번에 조회 (fetch join + projection)
    override fun findMatchCandidatesWithProfile(
        excludeUserIds: Set<String>,
        limit: Int,
    ): List<MatchCandidateDto> {
        val call = QCallEntity.callEntity
        val user = QUserEntity.userEntity
        val profile = QUserProfileEntity.userProfileEntity

        return queryFactory
            .select(
                Projections.constructor(
                    MatchCandidateDto::class.java,
                    call.id,
                    call.userId,
                    call.createdAt,
                    user.nickname,
                    user.gender,
                    user.birthYear,
                    profile.introduction,
                    profile.tags,
                )
            )
            .from(call)
            .innerJoin(user).on(call.userId.eq(user.id))
            .leftJoin(profile).on(call.userId.eq(profile.userId))
            .where(
                call.status.eq(CallStatus.WAITING),
                call.userId.notIn(excludeUserIds).takeIf { excludeUserIds.isNotEmpty() }
            )
            .orderBy(call.createdAt.asc()) // 오래 기다린 순
            .limit(limit.toLong())
            .fetch()
    }

    // 대기열 userId 목록만 조회 (Redis 동기화용)
    override fun findWaitingUserIds(): List<String> {
        val call = QCallEntity.callEntity
        return queryFactory
            .select(call.userId)
            .from(call)
            .where(call.status.eq(CallStatus.WAITING))
            .fetch()
    }
}
